// Ekstrak data dari payload WAHA (WhatsApp HTTP API)
// Referensi format: https://waha.devlike.pro/docs/how-to/webhooks/

const body = $input.item.json.body ?? $input.item.json;

// Hanya proses event 'message'
if (body?.event !== 'message') {
  return [{ json: { skip: true } }];
}

const payload = body.payload;

// Hanya proses pesan teks (type === 'chat'), bukan media/voice note/dsb
if (payload?.type !== 'chat') {
  return [{ json: { skip: true } }];
}

// Abaikan pesan dari bot sendiri
if (payload.fromMe) {
  return [{ json: { skip: true } }];
}

// Di grup: pengirim ada di payload.participant, bukan payload.from
// payload.from = ID grup (e.g. '120363xxx@g.us')
// payload.participant = nomor pengirim (e.g. '628xxx@c.us')
const rawPhone = payload.participant ?? payload.from;
const wa_phone = '+' + rawPhone.replace(/@c\.us$/, '').replace(/@g\.us$/, '');

// Nama kontak dari notifyName
const display_name = payload._data?.notifyName ?? 'Anggota';

// chat_id dipakai untuk kirim reply (ID grup atau nomor DM)
const chat_id = payload.from;

return [{
  json: {
    skip: false,
    wa_phone,
    display_name,
    text: payload.body,
    chat_id,
  }
}];

// Bangun prompt dan request body untuk Anthropic API
const waData = $('Ekstrak Data WA').item.json;
const text = waData.text;

const prompt = `Kamu adalah asisten parser untuk komunitas baca Silent Reading Club.

Tugasmu: ekstrak informasi dari pesan WhatsApp anggota komunitas dan kembalikan HANYA JSON valid (tanpa markdown code block, tanpa penjelasan tambahan apapun).

PESAN WHATSAPP:
${text}

FORMAT OUTPUT (hanya JSON murni, tidak ada teks lain):
{
  "book_title": "Judul buku yang disebutkan",
  "book_author": "Nama penulis, atau null jika tidak disebutkan",
  "content": "Catatan atau insight bacaan yang bersih dan informatif",
  "found_book": true
}

ATURAN:
- Pesan bisa campur bahasa Indonesia dan Inggris — keduanya valid
- Abaikan @bot, mention lain, dan kata sapaan seperti 'halo', 'guys', dll
- field "content" harus ditulis ulang menjadi catatan yang rapi dan bermanfaat, bukan copas mentah
- Jika tidak ada judul buku yang bisa diidentifikasi dengan jelas, kembalikan: {"found_book": false, "book_title": null, "book_author": null, "content": null}
- Hanya kembalikan field yang disebutkan di atas, tidak ada tambahan`;

const requestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];

// Parse respons JSON dari Claude
const response = $input.item.json;

if (!response?.content?.[0]?.text) {
  throw new Error('Respons Claude tidak valid: ' + JSON.stringify(response));
}

const rawText = response.content[0].text.trim();

// Bersihkan markdown code block jika ada
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Gagal parse JSON dari Claude: ' + cleaned);
}

if (!parsed.found_book || !parsed.book_title) {
  return [{ json: { skip: true } }];
}

const waData = $('Ekstrak Data WA').item.json;

return [{
  json: {
    skip: false,
    wa_phone: waData.wa_phone,
    display_name: waData.display_name,
    book_title: parsed.book_title,
    book_author: parsed.book_author ?? null,
    content: parsed.content,
    raw_message: waData.text,
  }
}];
